import React, { useState, useEffect } from "react";
import styles from "./BookingModal.module.css";
import { useLanguage } from "../../translet/LanguageContext";
import { useAuth } from "../../contexts/AuthContext";

const BookingModal = ({ isOpen, onClose, interpreter }) => {
  const { t } = useLanguage();
  const { user, isAuthenticated } = useAuth();

  const [formData, setFormData] = useState({
    serviceType: "",
    bookingType: "online", // online or offline
    location: "",
    startDate: "",
    startTime: "",
    endTime: "",
    topic: "",
    // Contact info (for non-authenticated users)
    fullName: user?.fullName || "",
    email: user?.email || "",
    phone: user?.phone || "",
  });

  const [errors, setErrors] = useState({});

  // Reset form when modal opens
  useEffect(() => {
    if (isOpen) {
      setFormData({
        serviceType: "",
        bookingType: "online",
        location: "",
        startDate: "",
        startTime: "",
        endTime: "",
        topic: "",
        fullName: user?.fullName || "",
        email: user?.email || "",
        phone: user?.phone || "",
      });
      setErrors({});
    }
  }, [isOpen, user]);

  // Prevent body scroll when modal is open
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "unset";
    }
    return () => {
      document.body.style.overflow = "unset";
    };
  }, [isOpen]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
    // Clear error for this field
    if (errors[name]) {
      setErrors((prev) => ({
        ...prev,
        [name]: "",
      }));
    }
  };

  const validateForm = () => {
    const newErrors = {};

    if (!formData.serviceType) {
      newErrors.serviceType = t("bookingModal.errors.serviceTypeRequired");
    }

    if (formData.bookingType === "offline" && !formData.location) {
      newErrors.location = t("bookingModal.errors.locationRequired");
    }

    if (!formData.startDate) {
      newErrors.startDate = t("bookingModal.errors.startDateRequired");
    }

    if (!formData.startTime) {
      newErrors.startTime = t("bookingModal.errors.startTimeRequired");
    }

    if (!formData.endTime) {
      newErrors.endTime = t("bookingModal.errors.endTimeRequired");
    }

    if (formData.startTime && formData.endTime && formData.startTime >= formData.endTime) {
      newErrors.endTime = t("bookingModal.errors.endTimeAfterStart");
    }

    if (!formData.topic || formData.topic.trim().length < 10) {
      newErrors.topic = t("bookingModal.errors.topicRequired");
    }

    // Validate contact info for non-authenticated users
    if (!isAuthenticated) {
      if (!formData.fullName || formData.fullName.trim().length < 2) {
        newErrors.fullName = t("bookingModal.errors.fullNameRequired");
      }

      if (!formData.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
        newErrors.email = t("bookingModal.errors.emailInvalid");
      }

      if (!formData.phone || !/^[0-9]{10,11}$/.test(formData.phone.replace(/\s/g, ""))) {
        newErrors.phone = t("bookingModal.errors.phoneInvalid");
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!validateForm()) {
      return;
    }

    // TODO: Submit booking to backend
    console.log("Booking submitted:", {
      ...formData,
      interpreterId: interpreter?.id,
      interpreterName: interpreter?.name,
    });

    // Show success message and close modal
    alert(t("bookingModal.successMessage"));
    onClose();
  };

  const handleOverlayClick = (e) => {
    if (e.target === e.currentTarget) {
      onClose();
    }
  };

  if (!isOpen) return null;

  return (
    <div className={styles.overlay} onClick={handleOverlayClick}>
      <div className={styles.modal}>
        {/* Header */}
        <div className={styles.header}>
          <div className={styles.titleSection}>
            <h2 className={styles.title}>{t("bookingModal.title")}</h2>
            <div className={styles.interpreterInfo}>
              {interpreter?.avatar && (
                <img
                  src={interpreter.avatar}
                  alt={interpreter.name}
                  className={styles.interpreterAvatar}
                />
              )}
              <p className={styles.interpreterName}>
                {t("bookingModal.bookingWith")} <strong>{interpreter?.name}</strong>
              </p>
            </div>
          </div>
          <button
            className={styles.closeButton}
            onClick={onClose}
            aria-label={t("bookingModal.close")}
          >
            ✕
          </button>
        </div>

        {/* Body - Form */}
        <form className={styles.form} onSubmit={handleSubmit}>
          {/* Service Type */}
          <div className={styles.formGroup}>
            <label htmlFor="serviceType" className={styles.label}>
              {t("bookingModal.serviceType")} <span className={styles.required}>*</span>
            </label>
            <select
              id="serviceType"
              name="serviceType"
              value={formData.serviceType}
              onChange={handleChange}
              className={`${styles.select} ${errors.serviceType ? styles.error : ""}`}
            >
              <option value="">{t("bookingModal.selectService")}</option>
              <option value="consecutive">{t("bookingModal.services.consecutive")}</option>
              <option value="simultaneous">{t("bookingModal.services.simultaneous")}</option>
              <option value="escort">{t("bookingModal.services.escort")}</option>
              <option value="online">{t("bookingModal.services.online")}</option>
            </select>
            {errors.serviceType && (
              <span className={styles.errorText}>{errors.serviceType}</span>
            )}
          </div>

          {/* Booking Type - Online/Offline */}
          <div className={styles.formGroup}>
            <label className={styles.label}>
              {t("bookingModal.bookingType")} <span className={styles.required}>*</span>
            </label>
            <div className={styles.radioGroup}>
              <label className={styles.radioLabel}>
                <input
                  type="radio"
                  name="bookingType"
                  value="online"
                  checked={formData.bookingType === "online"}
                  onChange={handleChange}
                  className={styles.radio}
                />
                <span>{t("bookingModal.online")}</span>
              </label>
              <label className={styles.radioLabel}>
                <input
                  type="radio"
                  name="bookingType"
                  value="offline"
                  checked={formData.bookingType === "offline"}
                  onChange={handleChange}
                  className={styles.radio}
                />
                <span>{t("bookingModal.offline")}</span>
              </label>
            </div>
          </div>

          {/* Location - Only show if Offline */}
          {formData.bookingType === "offline" && (
            <div className={styles.formGroup}>
              <label htmlFor="location" className={styles.label}>
                {t("bookingModal.location")} <span className={styles.required}>*</span>
              </label>
              <input
                type="text"
                id="location"
                name="location"
                value={formData.location}
                onChange={handleChange}
                placeholder={t("bookingModal.locationPlaceholder")}
                className={`${styles.input} ${errors.location ? styles.error : ""}`}
              />
              {errors.location && (
                <span className={styles.errorText}>{errors.location}</span>
              )}
            </div>
          )}

          {/* Start Date */}
          <div className={styles.formGroup}>
            <label htmlFor="startDate" className={styles.label}>
              {t("bookingModal.startDate")} <span className={styles.required}>*</span>
            </label>
            <input
              type="date"
              id="startDate"
              name="startDate"
              value={formData.startDate}
              onChange={handleChange}
              min={new Date().toISOString().split("T")[0]}
              className={`${styles.input} ${styles.dateInput} ${
                errors.startDate ? styles.error : ""
              }`}
            />
            {errors.startDate && (
              <span className={styles.errorText}>{errors.startDate}</span>
            )}
          </div>

          {/* Time Range */}
          <div className={styles.timeGroup}>
            <div className={styles.formGroup}>
              <label htmlFor="startTime" className={styles.label}>
                {t("bookingModal.startTime")} <span className={styles.required}>*</span>
              </label>
              <input
                type="time"
                id="startTime"
                name="startTime"
                value={formData.startTime}
                onChange={handleChange}
                className={`${styles.input} ${styles.timeInput} ${
                  errors.startTime ? styles.error : ""
                }`}
              />
              {errors.startTime && (
                <span className={styles.errorText}>{errors.startTime}</span>
              )}
            </div>

            <div className={styles.formGroup}>
              <label htmlFor="endTime" className={styles.label}>
                {t("bookingModal.endTime")} <span className={styles.required}>*</span>
              </label>
              <input
                type="time"
                id="endTime"
                name="endTime"
                value={formData.endTime}
                onChange={handleChange}
                className={`${styles.input} ${styles.timeInput} ${
                  errors.endTime ? styles.error : ""
                }`}
              />
              {errors.endTime && (
                <span className={styles.errorText}>{errors.endTime}</span>
              )}
            </div>
          </div>

          {/* Topic/Content */}
          <div className={styles.formGroup}>
            <label htmlFor="topic" className={styles.label}>
              {t("bookingModal.topic")} <span className={styles.required}>*</span>
            </label>
            <textarea
              id="topic"
              name="topic"
              value={formData.topic}
              onChange={handleChange}
              placeholder={t("bookingModal.topicPlaceholder")}
              rows={4}
              className={`${styles.textarea} ${errors.topic ? styles.error : ""}`}
            />
            {errors.topic && (
              <span className={styles.errorText}>{errors.topic}</span>
            )}
          </div>

          {/* Contact Information - Only for non-authenticated users */}
          {!isAuthenticated && (
            <>
              <div className={styles.divider}>
                <span>{t("bookingModal.contactInfo")}</span>
              </div>

              <div className={styles.formGroup}>
                <label htmlFor="fullName" className={styles.label}>
                  {t("bookingModal.fullName")} <span className={styles.required}>*</span>
                </label>
                <input
                  type="text"
                  id="fullName"
                  name="fullName"
                  value={formData.fullName}
                  onChange={handleChange}
                  placeholder={t("bookingModal.fullNamePlaceholder")}
                  className={`${styles.input} ${errors.fullName ? styles.error : ""}`}
                />
                {errors.fullName && (
                  <span className={styles.errorText}>{errors.fullName}</span>
                )}
              </div>

              <div className={styles.formGroup}>
                <label htmlFor="email" className={styles.label}>
                  {t("bookingModal.email")} <span className={styles.required}>*</span>
                </label>
                <input
                  type="email"
                  id="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  placeholder={t("bookingModal.emailPlaceholder")}
                  className={`${styles.input} ${errors.email ? styles.error : ""}`}
                />
                {errors.email && (
                  <span className={styles.errorText}>{errors.email}</span>
                )}
              </div>

              <div className={styles.formGroup}>
                <label htmlFor="phone" className={styles.label}>
                  {t("bookingModal.phone")} <span className={styles.required}>*</span>
                </label>
                <input
                  type="tel"
                  id="phone"
                  name="phone"
                  value={formData.phone}
                  onChange={handleChange}
                  placeholder={t("bookingModal.phonePlaceholder")}
                  className={`${styles.input} ${errors.phone ? styles.error : ""}`}
                />
                {errors.phone && (
                  <span className={styles.errorText}>{errors.phone}</span>
                )}
              </div>
            </>
          )}

          {/* Footer - Action Buttons */}
          <div className={styles.footer}>
            <button
              type="button"
              onClick={onClose}
              className={styles.cancelButton}
            >
              {t("bookingModal.cancel")}
            </button>
            <button type="submit" className={styles.submitButton}>
              {t("bookingModal.submit")}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default BookingModal;
